import { d3_ascending, d3_zoomIdentity } from '../../../../core/d3-constants';
import { getAxisObject } from '../../../../axis/axisutils';
import { getOrdinalRange } from '../../../../axis/scale';
import { pick } from '../../../../utils/zcutils';

/**
 *
 * @param chart
 * @param domain
 * @param axisType
 * @param index
 * @param selection
 * @return {*}
 */
export function getIdentity(chart, domain, axisType, index = 0, selection) {
    let rotated = chart.axes.rotated,
        brushedRange = selection || domainToActualRange(chart, domain, index, axisType);

    let dirType = {
        x: rotated ? 'y' : 'x',
        y: rotated ? 'x' : 'y'
    };

    let brushSize = (brushedRange[1] - brushedRange[0]) || 0.0001, //when both ranges are equal
        side = dirType[axisType] === 'x' ? 'width' : 'height',
        zoomScale = chart.plotarea[side] / brushSize,
        x = 0,
        y = 0;

    if (side === 'height') {
        y = -brushedRange[0];
    } else {
        x = -brushedRange[0];
    }

    return d3_zoomIdentity.scale(zoomScale).translate(x, y);
}

/**
 *
 * @param chart
 * @param domain
 * @param index
 * @param axisType
 * @param fixPadding
 * @param useBaseScale
 * @param scale0
 * @return {(number|*)[]}
 */
export function domainToActualRange(chart, domain, index, axisType, fixPadding, useBaseScale = true, scale0) {
    domain = [domain[0], domain[domain.length - 1]];
    let axisObj = getAxisObject(chart, axisType, index) || {},
        { scale, baseScale } = axisObj,
        range;

    scale = pick(scale0, useBaseScale ? baseScale : scale);
    range = domain.map(scale).sort(d3_ascending);

    if (scale.bandwidth) {
        // #ZC2251 $scale0
        range = fixBandRange(scale, scale0 || baseScale || scale, range, fixPadding, chart.axes.rotated);
    }

    return range;
}

/**
 *
 * @param scale
 * @param baseScale
 * @param plannerRange
 * @param fixPadding
 * @param rotated
 * @return {(number|*)[]}
 */
function fixBandRange(scale, baseScale, plannerRange, fixPadding = true, rotated) {
    let ordinalRange = getOrdinalRange(baseScale)
            .slice(0)
            .sort(d3_ascending),
        innerPadding = (ordinalRange[1] - ordinalRange[0] - baseScale.bandwidth()) / 2,
        outerPadding = scale.outerPaddingPx;

    if (fixPadding === false) {
        innerPadding = outerPadding = 0;
    }

    let size = baseScale.bandwidth(),
        start = ordinalRange[0] === plannerRange[0] ? plannerRange[0] - outerPadding : plannerRange[0] - innerPadding,
        end =
            ordinalRange[ordinalRange.length - 1] === plannerRange[1]
                ? plannerRange[1] + size + outerPadding
                : plannerRange[1] + size + innerPadding;

    return [start, end];
}
